{"path":"run.py","content":"from __future__ import annotations

import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int) -> None:
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")

    iterator = iter(tasks)
    running: set[asyncio.Task[None]] = set()
    cancelling = False

    def start_next() -> bool:
        nonlocal cancelling
        if cancelling:
            return False
        try:
            fn = next(iterator)
        except StopIteration:
            return False
        running.add(asyncio.create_task(fn()))
        return True

    for _ in range(min(max_concurrent, len(tasks))):
        if not start_next():
            break

    try:
        while running:
            done, _ = await asyncio.wait(running, return_when=asyncio.FIRST_COMPLETED)
            running.difference_update(done)

            first_error: BaseException | None = None
            for task in done:
                try:
                    await task
                except BaseException as exc:
                    if first_error is None:
                        first_error = exc

            if first_error is not None:
                cancelling = True
                for task in running:
                    task.cancel()
                if running:
                    await asyncio.gather(*running, return_exceptions=True)
                raise first_error

            while len(running) < max_concurrent and start_next():
                pass
    except asyncio.CancelledError:
        cancelling = True
        for task in running:
            task.cancel()
        if running:
            await asyncio.gather(*running, return_exceptions=True)
        raise
"}

